    {d:6.0,s:1350},{d:8.0,s:1270},{d:10.0,s:980},{d:12.0,s:880}
  ]}
};

let currentMat = 'SW-B';

function ge(id){ return document.getElementById(id); }
function fmt(v, n){ return (v===null||isNaN(v)||!isFinite(v)) ? '—' : v.toFixed(n); }

function getSigmaB(matKey, d){
  const tbl = MATS[matKey].sigma;
  if(!tbl) return 1200;
  for(let i=0;i<tbl.length;i++){
    if(d<=tbl[i].d) return tbl[i].s;
  }
  return tbl[tbl.length-1].s;
}

function selectMat(el){
  document.querySelectorAll('.mat-pill').forEach(p=>p.classList.remove('active'));
  el.classList.add('active');
  currentMat = el.dataset.mat;
  calc();
}

function onChipChange(){
  ge('chip-d-val').textContent  = ge('sel-d').value + ' mm';
  ge('chip-na-val').textContent = ge('sel-na').value + ' 巻';
  calc();
}

function calc(){
  const d  = parseFloat(ge('sel-d').value);
  const Na = parseFloat(ge('sel-na').value);
  const D  = parseFloat(ge('inp-D').value);
  const P  = parseFloat(ge('inp-P').value);
  const mat = MATS[currentMat];
  if(!mat){ setError('材料データが見つかりません'); return; }
  const G = mat.G;
  const sigmaB = getSigmaB(currentMat, d);

  // Validate
  if(isNaN(D)||D<=0||isNaN(P)||P<0||isNaN(d)||isNaN(Na)){
    setError('入力値を確認してください'); return;
  }

  // Core calculations (JIS B 2704)
  const C = D / d;                                           // ばね指数
  if(C < 2){ setError('ばね指数 C < 2: 線径が大きすぎます'); return; }
  const K  = (4*C-1)/(4*C-4) + 0.615/C;                    // Wahl係数
  const k  = G * Math.pow(d,4) / (8 * Math.pow(D,3) * Na); // ばね定数 (N/mm)
  const delta = k > 0 ? P / k : 0;                          // たわみ (mm)
  const tau = 8 * P * D * K / (Math.PI * Math.pow(d,3));    // 最大せん断応力 (MPa)
  const Lc  = (Na + 2) * d;                                 // 密着高さ (mm)
  const ratio = tau / sigmaB;                                // 応力比

  // Safety checks
  const stressOK = ratio <= 0.45;
  const cRange   = C >= 4 && C <= 14;
  const isSafe   = stressOK && cRange;

  // Badge
  const badge = ge('res-badge');
  if(isSafe){
    badge.className='result-badge badge-ok'; badge.textContent='安全 OK';
  } else if(!stressOK){
    badge.className='result-badge badge-ng'; badge.textContent='応力超過 NG';
  } else {
    badge.className='result-badge badge-warn'; badge.textContent='指数注意';
  }

  // Ratio bar
  const pct = Math.min(ratio / 0.45 * 100, 100);
  const barColor = ratio <= 0.35 ? '#1B6B3A' : ratio <= 0.45 ? '#F57C00' : '#C62828';
  ge('ratio-bar').style.width  = pct.toFixed(1) + '%';
  ge('ratio-bar').style.background = barColor;
  ge('res-ratio').textContent = fmt(ratio, 3);
  ge('res-ratio').style.color = barColor;

  // Sub results
  ge('res-k').textContent  = fmt(k, 3);
  ge('res-d').textContent  = fmt(delta, 2);
  ge('res-tau').textContent = fmt(tau, 1);
  ge('res-lc').textContent  = fmt(Lc, 2);

  // Warning
  const warnBox = ge('warn-box');
  const warnings = [];
  if(!stressOK)  warnings.push(`応力超過: τ/σB = ${fmt(ratio,4)} > 0.45。線径を太くするかコイル径を大きくしてください。`);
  if(C < 4)      warnings.push(`ばね指数 C = ${fmt(C,2)} < 4（推奨範囲）。コイル径を大きくするか線径を細くしてください。`);
  if(C > 14)     warnings.push(`ばね指数 C = ${fmt(C,2)} > 14（推奨範囲）。座屈リスクが増加します。`);
  if(warnings.length > 0){
    warnBox.classList.add('show');
    ge('warn-title').textContent = warnings.length > 1 ? `⚠ ${warnings.length}件の警告` : '⚠ 警告';
    ge('warn-detail').textContent = warnings.join(' / ');
  } else {
    warnBox.classList.remove('show');
  }

  // Detail rows
  const rows = [
    ['線径',        'd',          fmt(d,2),             'mm'],
    ['中心径',      'D',          fmt(D,2),             'mm'],
    ['外径',        'Do=D+d',     fmt(D+d,2),           'mm'],
    ['内径',        'Di=D-d',     fmt(D-d,2),           'mm'],
    ['有効巻数',    'Na',         fmt(Na,1),            '巻'],
    ['総巻数',      'Nt=Na+2',    fmt(Na+2,1),          '巻'],
    null,
    ['横弾性係数',  'G',          G.toLocaleString(),   'MPa'],
    ['引張強さ',    'σB',         sigmaB.toLocaleString(),'N/mm²'],
    ['ばね定数',    'k',          fmt(k,4),             'N/mm',  true],
    ['ばね指数',    'C=D/d',      fmt(C,3),             '—',     true],
    ['Wahl係数',    'K',          fmt(K,4),             '—',     true],
    null,
    ['荷重',        'P',          fmt(P,2),             'N'],
    ['たわみ',      'δ=P/k',      fmt(delta,3),         'mm',    true],
    ['せん断応力',  'τ',          fmt(tau,2),           'MPa',   true],
    ['応力比',      'τ/σB',       fmt(ratio,4),         '—',     true],
    null,
    ['密着高さ',    'Lc=(Na+2)d', fmt(Lc,2),            'mm'],
  ];

  let html = '';
  rows.forEach(r => {
    if(!r){ html += '<div class="detail-sep"></div>'; return; }
    const [name,sym,val,unit,hl] = r;
    html += `<div class="detail-row${hl?' hl':''}">
      <span class="detail-name">${name} <span class="detail-sym">${sym}</span></span>
      <span><span class="detail-val">${val}</span><span class="detail-unit">${unit}</span></span>
    </div>`;
  });
  ge('detail-inner').innerHTML = html;
}

function setError(msg){
  const badge = ge('res-badge');
  badge.className='result-badge badge-ng'; badge.textContent='入力エラー';
  ge('ratio-bar').style.width='0%';
  ge('res-ratio').textContent='—';
  ge('res-k').textContent=ge('res-d').textContent=ge('res-tau').textContent=ge('res-lc').textContent='—';
  ge('detail-inner').innerHTML=`<div style="font-size:11px;color:#A32D2D;text-align:center;padding:10px">${msg}</div>`;
  ge('warn-box').classList.remove('show');
}

function shareResult(){
  const d   = ge('sel-d').value;
  const Na  = ge('sel-na').value;
  const D   = ge('inp-D').value;
  const P   = ge('inp-P').value;
  const k   = ge('res-k').textContent;
  const tau = ge('res-tau').textContent;
  const rat = ge('res-ratio').textContent;
  const bdg = ge('res-badge').textContent;
  const lc  = ge('res-lc').textContent;
  const text = [
    'SpringSense コイルばね計算（JIS B 2704）',
    `材料: ${currentMat} / d=${d}mm / D=${D}mm / Na=${Na}`,
    `荷重: P=${P} N`,
    `ばね定数: k=${k} N/mm`,
    `せん断応力: τ=${tau} MPa（τ/σB=${rat}）`,
    `密着高さ: Lc=${lc} mm`,
    `判定: ${bdg}`
  ].join('\n');

  if(navigator.share){
    navigator.share({title:'SpringSense 計算結果', text});
  } else if(navigator.clipboard){
    navigator.clipboard.writeText(text).then(()=>alert('クリップボードにコピーしました'));
  }
}

// 初期化
onChipChange();
calc();
</script>
</body>

