// ── getSigmaB 境界値テスト
console.log('\n[getSigmaB 境界値テスト]');
checkEq('SW-B d=2.0 → 1470', Spring.getSigmaB('SW-B', 2.0), 1470);
checkEq('SW-B d=2.1 → 2.3行の1420', Spring.getSigmaB('SW-B', 2.1), 1420);
checkEq('SW-B d=13.0 → 1030', Spring.getSigmaB('SW-B', 13.0), 1030);
checkEq('SW-B d=99 → 1030（末尾）', Spring.getSigmaB('SW-B', 99), 1030);
checkEq('SUS304 d=2.0 → 1650', Spring.getSigmaB('SUS304-WPB', 2.0), 1650);

// ── エラーケース
console.log('\n[エラーケース]');
{
  const r1 = Spring.calc({ d: 4.0, D: 8, Na: 5, P: 100, mat: 'SW-B' });   // C=2 境界
  checkEq('C=2 → error', r1.error !== null, true);

  const r2 = Spring.calc({ d: 2.0, D: 15, Na: 5, P: 50, mat: 'UNKNOWN' });
  checkEq('不明材料 → error', r2.error !== null, true);
}

// ── Utils.fmt テスト
console.log('\n[Utils.fmt テスト]');
checkEq('fmt(1.23456, 3)', Utils.fmt(1.23456, 3), '1.235');
checkEq('fmt(NaN, 2)', Utils.fmt(NaN, 2), '—');
checkEq('fmt(Infinity, 2)', Utils.fmt(Infinity, 2), '—');
checkEq('fmt(null, 2)', Utils.fmt(null, 2), '—');

// ── モジュール構造テスト
console.log('\n[モジュール構造テスト]');
checkEq('MechSense.version', MechSense.version, '1.0.0');
checkEq('Spring.MATERIALS 件数', Object.keys(Spring.MATERIALS).length, 6);

// ── 結果サマリー
console.log(`\n${'='.repeat(50)}`);
console.log(`結果: ${passed} PASS / ${failed} FAIL`);
if (failed === 0) {
  console.log('✅ 全テスト PASS — mechsense-core.js は正確です');
} else {
  console.log('❌ 失敗あり — 計算ロジックを確認してください');
  process.exit(1);
}

